        int node = pq.top().second;
        pq.pop();

        if (node == n - 1) {
            return current_min;
        }

        if (min_edge_cost[node] < current_min) {
            continue;
        }

        for (auto& neighbor : adj[node]) {
            int v = neighbor.first;
            long long cost = neighbor.second;

            long long new_min = min(current_min, cost);
